6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
8	const BASE_PREMIUM: Record<string, number> = { sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25 };
9	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
10	const BLOCK_SIZE = 3;
11	const BLOCK_BASE_PREMIUM = 60;
12	
13	const sum = (numbers: number[]): number => numbers.reduce((a, b) => a + b, 0);
14	
15	const baseForItem = (item: Item): number => BASE_PREMIUM[item.type];
16	
17	const baseForComponentGroup = (count: number): number => {
18	  if (count === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
19	  return count * BASE_PREMIUM.rune;
20	};
21	
22	const groupByType = (items: Item[]): Map<string, Item[]> => {
23	  const groups = new Map<string, Item[]>();
24	  for (const item of items) {
25	    const list = groups.get(item.type) ?? [];
26	    list.push(item);
27	    groups.set(item.type, list);
28	  }
29	  return groups;
30	};
31	
32	const totalBaseForItems = (items: Item[]): number => {
33	  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
34	  const componentItems = items.filter((i) => COMPONENT_TYPES.has(i.type));
35	  const mainBase = sum(mainItems.map(baseForItem));
36	  const componentGroups = groupByType(componentItems);
37	  const componentBase = sum(
38	    Array.from(componentGroups.values()).map((group) => baseForComponentGroup(group.length)),
39	  );
40	  return mainBase + componentBase;
41	};
42	
43	const premiumForItem = (item: Item): number => {
44	  const base = BASE_PREMIUM[item.type];
45	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
46	};
47	
48	export const runScenario = (scenario: Scenario): { results: Result[] } => {
49	  const results = scenario.steps.map((step) => {
50	    const baseTotal = totalBaseForItems(step.items);
51	    const firstInsuranceTotal = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
52	    const total = baseTotal + firstInsuranceTotal + PROCESSING_FEE;
53	    return { premium: Math.ceil(total) };
54	  });
55	  return { results };
56	};
